{"code": "import json

# Read opportunities data
file_path = locals()['var_functions.query_db:8']
if isinstance(file_path, str):
    with open(file_path, 'r') as f:
        opportunities = json.load(f)
else:
    opportunities = locals()['var_functions.query_db:8']

# Read eligible contracts
eligible_contracts = locals()['var_functions.query_db:12']

# Clean IDs and filter opportunities linked to eligible contracts
eligible_contract_ids = set()
for contract in eligible_contracts:
    contract_id = contract['Id']
    # Remove leading # if present
    if contract_id.startswith('#'):
        contract_id = contract_id[1:]
    eligible_contract_ids.add(contract_id)

# Filter opportunities where ContractID__c is in eligible contracts
filtered_opps = []
for opp in opportunities:
    opp_contract_id = opp['ContractID__c']
    if opp_contract_id and opp_contract_id != 'None':
        # Clean opportunity contract ID
        if opp_contract_id.startswith('#'):
            opp_contract_id = opp_contract_id[1:]
        if opp_contract_id in eligible_contract_ids:
            filtered_opps.append(opp)

print("__RESULT__:")
print(json.dumps({
    "eligible_contracts_count": len(eligible_contract_ids),
    "total_opportunities": len(opportunities),
    "filtered_opportunities": len(filtered_opps),
    "sample_filtered": filtered_opps[:5] if filtered_opps else []
}, default=str, indent=2))"}
